head.script:
// 
/* global lay_hanjinSelfCls1, lay_lc_hanjinSelfCls1, tr_startPointCont1, tr_chassisNo1, tr_tel1, tr_overWidth2, tr_overLength2, tr_chassisNo2, lay_transWrkIndictNo2, lay_ed_transWrkIndictNo2, $c, dma_search, ds_resultsCopinoOut, ds_resultsCopinoIn, ed_sealNo2, lc_expimpClsCd1, lc_expimpClsCd2, td_sndClsCd1, td_sndClsCd2, chk_crryInCopino, tb_crryInCopino, tb_crryOutCopino, ed_tmlVsslPortcnt2, ed_dchrPort2, chk_crryOutCopino, lc_selfCls2, ed_emcId1, ed_emcId2, ed_dpctTransCoId1, ed_dpctTransCoId2, ed_transDstFrom1, ed_transDstTo2, img_transDstFromNm1, img_transDstToNm2, lc_fullEmptyClsCd2, wframe_title, udc_comCode, ed_vehclIdCardNo, ed_cntrNo, btnCreate, btnSave, btnSelect, hid_odrNo1, hid_odrNo2, hid_seq1, hid_seq2, hid_crryinCrryoutCls1, hid_crryinCrryoutCls2, hid_crryinoutCls1, hid_crryinoutCls2, ed_vsslArrvlportYr1, ed_vsslArrvlportYr2, hid_sndClsCd1, DsConstants, hid_sndClsCd2, hid_transCntSht1, hid_transCntSht2, ds_resultsCopinoIn2, ds_resultsCopinoOut2, sbm_retrieve2, sbm_retrieve, ed_vehclNoFrtcarNo1, ed_tmlVsslPortcnt1, ed_cntrNo1, ed_shpCoCd1, lc_fullEmptyClsCd1, ed_blNo1, ed_doNo1, ed_crryinoutDt1, ed_crryinoutHh1, hid_startPoint1, ed_mchtCd1, lc_chassisPosInfo1, hid_rcv1, hid_crryinoutDtmMint1, ed_vehclNoFull1, ed_sizTyp1, lc_drtCstmclrncExyn2, ed_vehclNoFrtcarNo2, ed_cntrNo2, ed_shpCoCd2, ed_blNo2, ed_doNo2, ed_bookingNo2, ed_totWt2, ed_crryinoutDt2, ed_crryinoutHh2, hid_rcv2, hid_crryinoutDtmMint2, ed_vehclNoFull2, ed_sizTyp2, dscommon */
/// 전역변수			
scwin.strId = "";
scwin.strRegNo = "";
scwin.gubun = "";
scwin.strEmc = "";
scwin.stref = "";

scwin.userClsCd;

scwin.vCurDate;
scwin.strCurYear;
scwin.nowTime;

scwin.toDay;
scwin.curDtm;

scwin.ed_srchSelfTransClntNoHide;

scwin.sealNo = "";

/**
 * @method
 * @name onpageload
 * @description 화면 로드 시 호출되는 이벤트 함수. 초기 컴포넌트들을 숨기고, 전역 변수 및 가용일자를 설정한다.
 * @param
 * @hidden N
 * @exception 
 * @example scwin.onpageload();
 */
scwin.onpageload = async function () {
    // 컴포넌트 초기 숨김 처리

    dscommon.cf_HideObject([lay_hanjinSelfCls1 ,lay_lc_hanjinSelfCls1, tr_startPointCont1, tr_chassisNo1, tr_tel1
                       ,tr_overWidth2 ,tr_overLength2, tr_chassisNo2,lay_transWrkIndictNo2,lay_ed_transWrkIndictNo2]);

    let param = $c.data.getParameter();
    scwin.strId = param.strId ?? "";
    scwin.strRegNo = param.strRegNo ?? ""
    scwin.gubun = param.gubun ?? ""
    scwin.stref = param.stref ?? ""

    // 가용일자
    let serverTime = $c.date.getServerDateTime("yyyyMMddHHmm");
    scwin.vCurDate = serverTime.substring(0, 8);
    scwin.strCurYear = serverTime.substring(0, 4);
    scwin.nowTime = serverTime.substring(8, 12);

    let dayIndex = Number($c.date.getDay(scwin.vCurDate, "num"));
    let weekDay = ["SUN", "MON", "TUE", "WED", "THU", "FRI", "SAT"];

    scwin.toDay = weekDay[dayIndex + 1];
    scwin.curDtm = serverTime;

    //사용자구분코드(01:그룹사구분코드(01:그룹사, 02:협력업체(운송), 03:선사, 04:화주, 05:자가운송업체, 06:렌터카(고객), 07:정비(고객))
    scwin.userClsCd = $c.data.getMemInfo("userClsCd");
    scwin.gv_userId = $c.data.getMemInfo("userId");
};

/**
 * @method
 * @name onUdcCompleted
 * @description UDC 컴포넌트 로드 완료 후 호출되는 함수. 데이터셋 초기화 및 화면 제어를 수행한다.
 * @param
 * @hidden N
 * @exception 
 * @example scwin.onUdcCompleted();
 */
scwin.onUdcCompleted = async function () {
    // 화면 UDC 로드 완료 후 데이터셋 초기화 및 반입/반출 구분에 따른 동작 제어

    // DataSet 초기화
    dma_search.reform();		// 조회조건 DataSet 초기화

    ds_resultsCopinoOut.removeAll();		// 반출(COPINO) DataSet 초기화
    ds_resultsCopinoOut.setRowPosition(ds_resultsCopinoOut.insertRow());

    ds_resultsCopinoIn.removeAll();		// 반입(COPINO) DataSet 초기화
    ds_resultsCopinoIn.setRowPosition(ds_resultsCopinoIn.insertRow());

    //f_create();
    scwin.f_defaultValue();
    ed_sealNo2.setMandatory(false);
    ed_sealNo2.setReadOnly(false);
    lc_expimpClsCd1.setMandatory(false);
    lc_expimpClsCd1.options.validExp = "수출입구분:no";
    lc_expimpClsCd2.setMandatory(false);
    lc_expimpClsCd2.options.validExp = "수출입구분:no";
    td_sndClsCd1.setValue("");
    td_sndClsCd2.setValue("");

    if (scwin.stref == "M") {
        chk_crryInCopino.setValue("1");;
        $c.gus.cfEnableObjects([tb_crryInCopino]);
        $c.gus.cfDisableObjects([tb_crryOutCopino]);
        ds_resultsCopinoOut.removeAll();		// 반출(COPINO) DataSet 초기화
        ed_tmlVsslPortcnt2.setValue("ODEM" + scwin.vCurDate.substring(4, 6));
        ed_dchrPort2.setValue("ZZZZZ");

    } else {
        chk_crryOutCopino.setValue("1");
        $c.gus.cfEnableObjects([tb_crryOutCopino]);
        $c.gus.cfDisableObjects([tb_crryInCopino]);
        ds_resultsCopinoIn.removeAll();		// 반입(COPINO) DataSet 초기화	    
    }

    if ("" != scwin.strRegNo) {
        await scwin.searchClnt();
    }

    lc_selfCls2.setValue("Y");
    lc_selfCls2.setDisabled(true);;

    ed_emcId1.setValue(scwin.strEmc);
    ed_emcId2.setValue(scwin.strEmc);
    ed_dpctTransCoId1.setValue(scwin.strId.toUpperCase());

    ed_dpctTransCoId2.setValue(scwin.strId.toUpperCase());
    ed_dpctTransCoId1.setValue(scwin.gv_userId.toUpperCase());
    ed_dpctTransCoId2.setValue(scwin.gv_userId.toUpperCase());

    ed_transDstFrom1.setValue("5P01");
    ed_transDstTo2.setValue("5P01");
    ed_transDstFrom1.setReadOnly(true);
    ed_transDstTo2.setReadOnly(true);

    $c.gus.cfDisableObjects([img_transDstFromNm1]);
    // 화면 UDC 로드 완료 후 데이터셋 초기화 및 반입/반출 구분에 따른 동작 제어

    // DataSet 초기화
    dma_search.reform();		// 조회조건 DataSet 초기화

    ds_resultsCopinoOut.removeAll();		// 반출(COPINO) DataSet 초기화
    ds_resultsCopinoOut.setRowPosition(ds_resultsCopinoOut.insertRow());

    ds_resultsCopinoIn.removeAll();		// 반입(COPINO) DataSet 초기화
    ds_resultsCopinoIn.setRowPosition(ds_resultsCopinoIn.insertRow());

    //f_create();
    scwin.f_defaultValue();
    ed_sealNo2.setMandatory(false);
    ed_sealNo2.setReadOnly(false);
    lc_expimpClsCd1.setMandatory(false);
    lc_expimpClsCd1.options.validExp = "수출입구분:no";
    lc_expimpClsCd2.setMandatory(false);
    lc_expimpClsCd2.options.validExp = "수출입구분:no";
    td_sndClsCd1.setValue("");
    td_sndClsCd2.setValue("");

    if (scwin.stref == "M") {
        chk_crryInCopino.setValue("1");;
        $c.gus.cfEnableObjects([tb_crryInCopino]);
        $c.gus.cfDisableObjects([tb_crryOutCopino]);
        ds_resultsCopinoOut.removeAll();		// 반출(COPINO) DataSet 초기화
        ed_tmlVsslPortcnt2.setValue("ODEM" + scwin.vCurDate.substring(4, 6));
        ed_dchrPort2.setValue("ZZZZZ");

    } else {
        chk_crryOutCopino.setValue("1");
        $c.gus.cfEnableObjects([tb_crryOutCopino]);
        $c.gus.cfDisableObjects([tb_crryInCopino]);
        ds_resultsCopinoIn.removeAll();		// 반입(COPINO) DataSet 초기화	    
    }

    if ("" != scwin.strRegNo) {
        await scwin.searchClnt();
    }

    lc_selfCls2.setValue("Y");
    lc_selfCls2.setDisabled(true);;

    ed_emcId1.setValue(scwin.strEmc);
    ed_emcId2.setValue(scwin.strEmc);
    ed_dpctTransCoId1.setValue(scwin.strId.toUpperCase());

    ed_dpctTransCoId2.setValue(scwin.strId.toUpperCase());
    ed_dpctTransCoId1.setValue(scwin.gv_userId.toUpperCase());
    ed_dpctTransCoId2.setValue(scwin.gv_userId.toUpperCase());

    ed_transDstFrom1.setValue("5P01");
    ed_transDstTo2.setValue("5P01");
    ed_transDstFrom1.setReadOnly(true);
    ed_transDstTo2.setReadOnly(true);

    $c.gus.cfDisableObjects([img_transDstFromNm1]);
    $c.gus.cfDisableObjects([img_transDstToNm2]);
    lc_fullEmptyClsCd2.setValue("4");
    $c.gus.cfDisableObjects([lc_fullEmptyClsCd2]);

    let paramTitle = "EVER 반출입예정정보EDI강제등록";
    wframe_title.getAllChildren().forEach(function(value){
        if(value.getOriginalID() == "txt_h1") {
            value.setValue(paramTitle);
            return false;
        }
    });
};

/**
 * @method
 * @name searchClnt
 * @description 차량 또는 컨테이너의 거래처를 검색하고 확인하는 함수.
 * @param
 * @hidden N
 * @exception 
 * @example await scwin.searchClnt();
 */
scwin.searchClnt = function () {
    // 거래처 정보를 찾기 위한 팝업 호출 및 콜백 처리
    return new Promise(function (resolve, reject) {
        let txt = "";
        let v_strRegNo = scwin.strRegNo.split("-");

        for (let i = 0; i < v_strRegNo.length; i++) {
            txt += v_strRegNo[i];
        }

        let pCode = txt;
        let pName = "";
        let pClose = "T";
        let pAllSearch = "F";
        udc_comCode.setSelectId('retrieveClntNoFind')   // XML상의 SELECT ID
        udc_comCode.cfCommonPopUpAsyncAsync(
            async function (rtnList) {
                try {
                    if (rtnList != null) {
                        scwin.ed_srchSelfTransClntNoHide = rtnList[0];
                    }
                    if (rtnList == "N/A") {
                        scwin.ed_srchSelfTransClntNoHide = "";
                        await $c.win.alert("DPCT 거래처 등록을 확인해주세요, \n 자가담당자에게 거래처등록을 요청하세요");
                        $c.gus.cfDisableObjects([ed_vehclIdCardNo, ed_cntrNo]);
                        $c.gus.cfDisableBtn([btnCreate, btnSave, btnSelect]);
                    }
                    resolve(rtnList);
                } catch (e) {
                    console.error("cfCommonPopUpAsync Error:", e);
                    reject(e); // 에러 발생 시 처리
                }
            }
            , pCode					// 화면에서의 ??? Code Element의	Value
            , pName					// 화면에서의 ??? Name Element의	Value
            , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
            , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
            , null					// Title순서	
            , null					// 보여주는 각 컬럼들의 폭	
            , null					// 컬럼중에서 숨기는	컬럼 지정	
            , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
            , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
            , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
            , null					// 윈도우 위치 Y좌표	
            , null					// 윈도우 위치 X좌표
            , null					// 중복체크여부	("F")
            , pAllSearch					// 전체검색허용여부	("F")
            , ""				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
    });
};

/**
 * @method
 * @name f_defaultValue
 * @description 초기값 설정
 * @param
 * @hidden N
 * @exception 
 * @example scwin.f_defaultValue();
 */ 
scwin.f_defaultValue = function () {

    // 오더번호 강제 설정 
    hid_odrNo1.setValue("9999999999999");
    hid_odrNo2.setValue("9999999999999");

    // 순번 설정
    hid_seq1.setValue(0);
    hid_seq2.setValue(0);

    // 반입/반출구분, 반출입구분 설정
    hid_crryinCrryoutCls1.setValue("1");	// 반출 (1)
    hid_crryinCrryoutCls2.setValue("2");	// 반입 (2)

    hid_crryinoutCls1.setValue("1");	// 반출 (1)
    hid_crryinoutCls2.setValue("2");	// 반입 (2)

    // 모선입항년도 설정
    ed_vsslArrvlportYr1.setValue(scwin.strCurYear);
    ed_vsslArrvlportYr2.setValue(scwin.strCurYear);

    // 전송구분
    hid_sndClsCd1.setValue(DsConstants.EDI_SND_CLS_CD_SND_WAIT);	// EDI전송구분 : 전송대기(0)
    hid_sndClsCd2.setValue(DsConstants.EDI_SND_CLS_CD_SND_WAIT);	// EDI전송구분 : 전송대기(0)

    // 운송수단
    hid_transCntSht1.setValue("3");
    hid_transCntSht2.setValue("3");
};

/**
 * @method
 * @name f_create
 * @description 신규
 * @param
 * @hidden N
 * @exception 
 * @example scwin.f_create();
 */ 
scwin.f_create = async function () {

    // DataSet 초기화
    dma_search.reform();		// 조회조건 DataSet 초기화

    ds_resultsCopinoOut.removeAll();		// 반출(COPINO) DataSet 초기화
    ds_resultsCopinoOut.setRowPosition(ds_resultsCopinoOut.insertRow());

    ds_resultsCopinoIn.removeAll();		// 반입(COPINO) DataSet 초기화
    ds_resultsCopinoIn.setRowPosition(ds_resultsCopinoIn.insertRow());

    // 조회조건 초기화
    scwin.f_FieldClear();

    // 초기값 설정
    scwin.f_defaultValue();

    $c.gus.cfEnableBtnOnly([btnCreate]);	// 버튼 활성화
    $c.gus.cfEnableBtnOnly([btnSave]);	// 버튼 활성화

    chk_crryInCopino.setValue("1");
    chk_crryOutCopino.setValue("1");
    scwin.f_switchTransYn(2);
    scwin.f_switchTransYn(1);

    ed_sealNo2.setMandatory(false);
    ed_sealNo2.setReadOnly(false);
    lc_expimpClsCd1.setMandatory(false);
    lc_expimpClsCd1.options.validExp = "수출입구분:no";
    lc_expimpClsCd2.setMandatory(false);
    lc_expimpClsCd2.options.validExp = "수출입구분:no";
};

/**
 * @method
 * @name f_Retrieve
 * @description 조회
 * @param
 * @hidden N
 * @exception 
 * @example scwin.f_Retrieve();
 */ 
scwin.f_Retrieve = async function (gubun) {
    if ((ed_vehclIdCardNo.getValue() == null || ed_vehclIdCardNo.getValue() == "") &&
        (ed_cntrNo.getValue() == null || ed_cntrNo.getValue() == "")) {
        await $c.gus.cfAlertMsg("조회시 차량 ID와 CNTR_NO 중 둘중에 하나 기입해야 합니다.");
        return false;
    }

    if (ed_vehclIdCardNo.getValue() != null && ed_vehclIdCardNo.getValue() != "") {
        if (ed_vehclIdCardNo.getValue().length != 8) {
            await $c.gus.cfAlertMsg("조회시 차량 ID는  8자리를  기입해야 합니다.");
            return false;
        }
    }
    if (ed_cntrNo.getValue() != null && ed_cntrNo.getValue() != "") {

        if (ed_cntrNo.getValue().length != 11) {
            await $c.gus.cfAlertMsg("조회시 컨테이너는 번호는 11자리를  기입해야 합니다.");
            return false;
        }
    }

    if (gubun == undefined || gubun == null || gubun == "" || gubun == 0) {
        ds_resultsCopinoOut.removeAll();
        ds_resultsCopinoIn.removeAll();

        let rtn = await $c.sbm.execute(sbm_retrieve);
        if (rtn.responseJSON.resultDataSet[0].Code == 0) { //성공시
            $c.gus.cfEnableBtnOnly([btnCreate, btnSave]);	// 버튼 활성화
        }
    } else {
        if (chk_crryInCopino.getValue() == "") {
            ds_resultsCopinoIn2.removeAll();
            if (chk_crryOutCopino.getValue() == "1") {
                ds_resultsCopinoOut.setJSON([ds_resultsCopinoOut2.getRowJSON(0)]);

                let rtn = await $c.sbm.execute(sbm_retrieve2);
                scwin.sbm_retrieve2_submitdone(rtn);

            }
        }
        if (chk_crryOutCopino.getValue() == "") {
            ds_resultsCopinoOut2.removeAll();
            if (chk_crryInCopino.getValue() == "1") {
                ds_resultsCopinoIn.setJSON([ds_resultsCopinoIn2.getRowJSON(0)]);

                let rtn = await $c.sbm.execute(sbm_retrieve2);
                scwin.sbm_retrieve2_submitdone(rtn);
            }
        }

    }

    if (ds_resultsCopinoIn.getRowCount() == 0 && ds_resultsCopinoOut.getRowCount() == 0) {
        ds_resultsCopinoOut.removeAll();
        ds_resultsCopinoOut.setRowPosition(ds_resultsCopinoOut.insertRow());
        ds_resultsCopinoIn.removeAll();
        ds_resultsCopinoIn.setRowPosition(ds_resultsCopinoIn.insertRow());
        scwin.f_defaultValue();
    } else if (ds_resultsCopinoOut.getRowCount() == 0) {
        ds_resultsCopinoOut.removeAll();
        ds_resultsCopinoOut.setRowPosition(ds_resultsCopinoOut.insertRow());
        scwin.f_defaultValue();
    } else if (ds_resultsCopinoIn.getRowCount() == 0) {
        ds_resultsCopinoIn.removeAll();
        ds_resultsCopinoIn.setRowPosition(ds_resultsCopinoIn.insertRow());
        scwin.f_defaultValue();
    }

    //await scwin.lc_fullEmptyClsCd1_onchange();
    //await scwin.lc_fullEmptyClsCd2_onchange();

    if(scwin.sealNo != "" && gubun == undefined ) {
        ed_sealNo2.setValue(scwin.sealNo);    //ASIS는 lc_fullEmptyClsCd2_onchange 함수가 데이터 세팅 전에 호출되는 차이가 있어 일부러 다시 한번 세팅한다.
        scwin.sealNo = "";
    }

    ed_transDstFrom1.setValue("5P01");
    ed_transDstTo2.setValue("5P01");
    lc_fullEmptyClsCd2.setValue("4");
    $c.gus.cfDisableObjects([lc_fullEmptyClsCd2]);
};

/**
 * @method
 * @name sbm_retrieve2_submitdone
 * @description sbm_retrieve2 조회 후 후처리 작업 함수
 * @param rtn sbm_retrieve2의 리턴값
 * @hidden Y
 * @exception 
 */ 
scwin.sbm_retrieve2_submitdone = function (rtn) {
    if (rtn.responseJSON.resultDataSet[0].Code == 0) { //성공시
        $c.gus.cfEnableBtnOnly([btnCreate, btnSave]);	// 버튼 활성화

        if (chk_crryInCopino.getValue() == "") {
            ds_resultsCopinoIn2.removeAll();
            if (chk_crryOutCopino.getValue() == "1") {
                ds_resultsCopinoOut.setJSON([ds_resultsCopinoOut2.getRowJSON(0)]);
            }
        }

        if (chk_crryOutCopino.getValue() == "") {
            ds_resultsCopinoOut2.removeAll();
            if (chk_crryInCopino.getValue() == "1") {
                ds_resultsCopinoIn.setJSON([ds_resultsCopinoIn2.getRowJSON(0)]);
            }
        }
    }
};

/**
 * @method
 * @name f_validate
 * @description 필수값체크 함수
 * @param 
 * @hidden N
 * @exception 
 * @example scwin.f_validate();
 */ 
scwin.f_validate = async function () {
    lc_expimpClsCd1.setMandatory(true);
    lc_expimpClsCd1.options.validExp = "수출입구분:yes";
    lc_expimpClsCd2.setMandatory(true);
    lc_expimpClsCd2.options.validExp = "수출입구분:yes";

    //반출
    if (chk_crryOutCopino.getValue() == "1") {
