                ed_shpCoCd1.options.validExp = "OPERATOR:yes";
            }


            if (!$c.gus.cfIsNull(ed_transDstFrom1.getValue())) {
                // 수신자 <- 출발지 설정
                hid_rcv1.setValue(ed_transDstFrom1.getValue());
            } else {
                hid_rcv1.setValue("");
            }
            if (ed_tmlVsslPortcnt1.getValue().length == 5) {
