                return false;
            } else {
                //가운데 숫자체크
                if (!(Number(ed_vehclNoFull1.getValue().substring(2, 4)) >= 0
                    && Number(ed_vehclNoFull1.getValue().substring(2, 4)) <= 99
                    && ed_vehclNoFull1.getValue().substring(2, 4).length == 2)) {
                    await $c.win.alert("세번째 네번째는 숫자이어야 합니다. ");
                    return false;
                }
                //마지막 네자리 숫자 체트
                if (!(Number(ed_vehclNoFull1.getValue().substring(5, 10)) >= 0
                    && Number(ed_vehclNoFull1.getValue().substring(5, 10)) <= 9999
