                || sizTyp1 == "2232"
                || sizTyp1 == "2251"
                || sizTyp1 == "2264"
                || sizTyp1 == "4310"
                || sizTyp1 == "4370"
                || sizTyp1 == "4332"
                || sizTyp1 == "4351"
                || sizTyp1 == "4364"
                || sizTyp1 == "4510"
                || sizTyp1 == "9510"
                || sizTyp1 == "4532"
                || sizTyp1 == "4350"
                || sizTyp1 == "2250")) {
