            }
            //alert("kkk2-1");
            if (!$c.gus.cfIsNull(lc_expimpClsCd2.getValue()) && (lc_expimpClsCd2.getValue() == "I")) {
                //alert("kkk2-2");            
                if ($c.gus.cfIsNull(ed_blNo2.getValue())) {

                    await $c.win.alert("BL/NO를 반드시 입력하세요 .");
                    return false;
                }

                if ($c.gus.cfIsNull(ed_doNo2.getValue())) {
                    await $c.win.alert("DO/NO를 반드시 입력하세요 .");
