            if (ds_resultsCopinoIn.getCellData(0, "fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL
                && (ds_resultsCopinoIn.getCellData(0, "totWt") == 0 || ds_resultsCopinoIn.getCellData(0, "totWt") == "")) {
                await $c.win.alert("[E/F 구분]이 FULL 일때 [WEIGHT]는 필수입니다");
                return false;
            }
            //[사전정보그룹구분=터미널]이면 차량ID를 입력받아야함
            if (ds_resultsCopinoIn.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM
                && ds_resultsCopinoIn.getCellData(0, "vehclIdCardNo") == "") {
                await $c.win.alert("[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다");
                return false;
            }
            //[사전정보그룹구분=터미널]이면 모선/항차를 입력받아야함
            if (ds_resultsCopinoIn.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM
                && ds_resultsCopinoIn.getCellData(0, "tmlVsslPortcnt") == "") {
                await $c.win.alert("[사전정보그룹구분]이 터미널 일때 [모선/항차]는 필수입니다");
                return false;
            }
            //[full/empty구분=full]이면 SEAL NO를 입력받아야함

            if (chk_crryInCopino.getValue() == "1") {
                ds_resultsCopinoIn2.setJSON([ds_resultsCopinoIn.getRowJSON(0)]);
            }
            if (chk_crryInCopino.getValue() == "") {
                ds_resultsCopinoIn2.removeAll();
            }

            if (ed_vehclNoFull2.getValue().length != 9) {
                await $c.win.alert("차량번호는 FULL NAME을 정확히 입력하세요  예)경기98자1234");
                return false;
            } else {
                //가운데 숫자체크
                if (!(Number(ed_vehclNoFull2.getValue().substring(2, 4)) >= 0
                    && Number(ed_vehclNoFull2.getValue().substring(2, 4)) <= 99
                    && ed_vehclNoFull2.getValue().substring(2, 4).length == 2)) {
                    await $c.win.alert("세번째 네번째는 숫자이어야 합니다. ");
                    return false;
                }
                //마지막 네자리 숫자 체트
                if (!(Number(ed_vehclNoFull2.getValue().substring(5, 10)) >= 0
                    && Number(ed_vehclNoFull2.getValue().substring(5, 10)) <= 9999
                    && ed_vehclNoFull2.getValue().substring(5, 10).length == 4)) {
                    await $c.win.alert("끝에 네자리는 숫자이어야 합니다. ");
                    return false;
                }

                //처음2자리 문자자체크
                let kk = ed_vehclNoFull2.getValue().substring(0, 2);

                if (kk == null) {
                    return false;
                }

                for (let i = 0; i < kk.length; i++) {

                    let c = kk.charCodeAt(i);

                    if (!((0xAC00 <= c && c <= 0xD7A3) || (0x3131 <= c && c <= 0x318E))) {
                        await $c.win.alert("처음2자리 한글이어야 합니다.!!! ");
                        return false;
                    }
                }
                //가운데1자리 문자자체크
                let kkk = ed_vehclNoFull2.getValue().substring(4, 5);

                if (kkk == null) {
                    return false;
                }

                for (let i = 0; i < kkk.length; i++) {

                    let c = kkk.charCodeAt(i);

                    if (!((0xAC00 <= c && c <= 0xD7A3) || (0x3131 <= c && c <= 0x318E))) {
                        await $c.win.alert("다서번째는 한글이어야 합니다.!!! ");
                        return false;
                    }
                }
            }

            let sizTyp2 = ed_sizTyp2.getValue();
            if (sizTyp2 == "2210"
                || sizTyp2 == "2270"
                || sizTyp2 == "2232"
                || sizTyp2 == "2251"
                || sizTyp2 == "2264"
                || sizTyp2 == "4310"
                || sizTyp2 == "4370"
                || sizTyp2 == "4332"
                || sizTyp2 == "4351"
                || sizTyp2 == "4364"
                || sizTyp2 == "4510"
                || sizTyp2 == "9510"
                || sizTyp2 == "4532"
                || sizTyp2 == "4350"
                || sizTyp2 == "2250") {

                if (sizTyp2 == "2210") {
                    ed_totWt2.setValue(2400);
                } else if (sizTyp2 == "2270") {

                } else if (sizTyp2 == "2232") {
                    ed_totWt2.setValue(3020);
                } else if (sizTyp2 == "2251") {
                    ed_totWt2.setValue(2330);
                } else if (sizTyp2 == "2790") {

                } else if (sizTyp2 == "4310") {
                    ed_totWt2.setValue(4000);
                } else if (sizTyp2 == "4370") {

                } else if (sizTyp2 == "4332") {
                    ed_totWt2.setValue(4760);
                } else if (sizTyp2 == "4351") {
                    ed_totWt2.setValue(4060);
                } else if (sizTyp2 == "4364") {

                } else if (sizTyp2 == "4510") {
                    ed_totWt2.setValue(4200);
                } else if (sizTyp2 == "9510") {
                    ed_totWt2.setValue(4700);
                } else if (sizTyp2 == "4532") {
                    ed_totWt2.setValue(4760);
                } else if (sizTyp2 == "4350") {
                    ed_totWt2.setValue(4060);
                } else if (sizTyp2 == "2250") {
                    ed_totWt2.setValue(2330);
                }
            } else {
                await $c.win.alert("SIZ/TYPE을 정확하게 입력하세요!!!");
                ed_sizTyp2.focus();
                return false;
            }


        }
    }

    let sizTyp2 = ed_sizTyp2.getValue();
    if (sizTyp2 == "2232" || sizTyp2 == "4332" || sizTyp2 == "4532") {
        if (ed_frzTemper2.getValue() == "") {
            await $c.win.alert("냉동컨테이너 입력시 온도는 필수 입력 사항입니다.");
            ed_frzTemper2.focus();
            return false;
        }
        if (ed_rmk3.getValue() == "") {
            await $c.win.alert("냉동컨테이너 입력시 DRY/CEL은 필수 입력 사항입니다.");
            ed_rmk3.focus();
            return false;
        }
    }

    if (ed_shpCoCd1.getValue() == "HML" || ed_shpCoCd1.getValue() == "EMC"
        || ed_shpCoCd1.getValue() == "ITS" || ed_shpCoCd1.getValue() == "EMS" || ed_shpCoCd1.getValue() == "EGH") {
        if (lc_expimpClsCd1.getValue() == "I") {

            if (ed_doNo1.getValue() == "" || $c.gus.cfIsNull(ed_doNo1.getValue())) {
                await $c.win.alert("D/O NO 는 필수입니다");
                return false;
            }
            if (ed_blNo1.getValue() == "" || $c.gus.cfIsNull(ed_blNo1.getValue())) {
                await $c.win.alert("BL NO 는 필수입니다");
                return false;
            }

        }
    }

    if (ed_shpCoCd2.getValue() == "HML" || ed_shpCoCd2.getValue() == "EMC"
        || ed_shpCoCd2.getValue() == "ITS" || ed_shpCoCd2.getValue() == "EMS" || ed_shpCoCd2.getValue() == "EGH") {
        if (lc_expimpClsCd2.getValue() == "I") {

            if (ed_doNo2.getValue() == "" || $c.gus.cfIsNull(ed_doNo2.getValue())) {
