/**
 * @method
 * @name f_switchTransYn
 * @description 전송여부 switch
 * @param gubun 구분
 * @hidden Y
 * @exception 
 * @example scwin.f_switchTransYn(1);
 */ 
scwin.f_switchTransYn = function (gubun) {
    if (gubun == 1) {
        if (chk_crryOutCopino.getValue() == "1") {
            ds_resultsCopinoOut.removeAll();		// 반출(COPINO) DataSet 초기화
            ds_resultsCopinoOut.setRowPosition(ds_resultsCopinoOut.insertRow());
            $c.gus.cfEnableObjects([tb_crryOutCopino]);
            ed_transDstFrom1.setValue("5P01");
            ed_transDstFrom1.setReadOnly(true);
            $c.gus.cfDisableObjects([img_transDstFromNm1]);
        } else {
            $c.gus.cfDisableObjects([tb_crryOutCopino]);
            ds_resultsCopinoOut.removeAll();		// 반출(COPINO) DataSet 초기화
            //ds_resultsCopinoIn.removeAll();		// 반입(COPINO) DataSet 초기화	    
            ds_resultsCopinoOut2.removeAll();
            ed_transDstFrom1.setValue("5P01");
        }


    } else if (gubun == 2) {
        if (chk_crryInCopino.getValue() == "1") {
            ds_resultsCopinoIn.removeAll();		// 반입(COPINO) DataSet 초기화
            ds_resultsCopinoIn.setRowPosition(ds_resultsCopinoIn.insertRow());
            $c.gus.cfEnableObjects([tb_crryInCopino]);
            ed_transDstTo2.setValue("5P01");
            ed_transDstTo2.setReadOnly(true);
            $c.gus.cfDisableObjects([img_transDstToNm2]);
        } else {
            $c.gus.cfDisableObjects([tb_crryInCopino]);
            ds_resultsCopinoIn.removeAll();		// 반입(COPINO) DataSet 초기화	    
            //ds_resultsCopinoOut.removeAll();		// 반출(COPINO) DataSet 초기화
            ds_resultsCopinoIn2.removeAll();
            ed_transDstTo2.setValue("5P01");
        }


    }
    scwin.f_defaultValue();

};

