/**
 * @method
 * @name ds_resultsCopinoOut_ondataload
 * @description 반출(COPINO) DataSet ondataload 이벤트 핸들러 함수
 * @hidden Y
 * @exception 
 */ 
scwin.ds_resultsCopinoOut_ondataload = async function () {
    let rowCnt = ds_resultsCopinoOut.getRowCount();
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    ds_resultsCopinoOut.setRowPosition(0);

    //반출
    let sndDtHh1 = (ds_resultsCopinoOut.getCellData(0, "sndDt") == "" ? "" : $c.gus.cfGetFormatStr(ds_resultsCopinoOut.getCellData(0, "sndDt"), "####/##/##"))
        + " " + (ds_resultsCopinoOut.getCellData(0, "sndHh") == "" ? "" : $c.gus.cfGetFormatStr(ds_resultsCopinoOut.getCellData(0, "sndHh"), "##:##:##"))
        ;
    td_sndDtHh1.setValue(sndDtHh1);

    if (ds_resultsCopinoOut.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE) {
        td_sndClsCd1.setValue("전송완료");
        td_sndClsCd1.setStyle("color", "red");
    } else if (ds_resultsCopinoOut.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_LATER_SND) {
        td_sndClsCd1.setValue("사후전송");
        td_sndClsCd1.setStyle("color", "red");
    } else if (ds_resultsCopinoOut.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_IMPITEM_WARN) {
        td_sndClsCd1.setValue("필수입력오류");
        td_sndClsCd1.setStyle("color", "red");
    } else if (ds_resultsCopinoOut.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_WAIT) {
        td_sndClsCd1.setValue("전송대기");
        td_sndClsCd1.setStyle("color", "red");
    } else {
        td_sndClsCd1.setValue("미등록");
        td_sndClsCd1.setStyle("color", "red");
    }

    //[사전정보그룹구분코드=경인ICD and 작업단계코드<>철송]
    if (ds_resultsCopinoOut.getCellData(0, "preInfoGrpClsCd") == DsConstants.EDI_GRPCD_KYUNGIN_ICD
        && ds_resultsCopinoOut.getCellData(0, "wrkStpCd") != DsConstants.WRK_STP_CD_RAILROAD) {
        $c.gus.cfDisableObjects([ed_vehclNoFrtcarNo1]);
    }

    var crryinoutDtmMint1_Date = hid_crryinoutDtmMint1.getValue().toDate("YYYYMMDDHHmm");
    ed_crryinoutDt1.setValue(crryinoutDtmMint1_Date.format("YYYYMMDD"));
    ed_crryinoutHh1.setValue(crryinoutDtmMint1_Date.format("HHmm"));
};

