scwin.lc_fullEmptyClsCd2_onchange = async function (info) {
    if (ds_resultsCopinoIn.getRowCount() > 0) {
        let fullEmptyClsCd = lc_fullEmptyClsCd2.getValue();
        if (fullEmptyClsCd == "4") {
            ed_sealNo2.setValue(" ");
            // EMPTY 인 경우 : WEIGHT 선택 
            ed_totWt2.setMandatory(false);
            ed_totWt2.options.validExp = "WEIGHT:no";
        } else if (fullEmptyClsCd == "5") {
            // 5 : FULL
            ed_sealNo2.setReadOnly(false);	// SEAL NO
            // FULL 인 경우 : WEIGHT 필수 
            ed_totWt2.setMandatory(true);
            ed_totWt2.options.validExp = "WEIGHT:yes";
        } else {
            // E/F 구분을(를) 선택하십시오.
            debugger;
            await $c.win.alert($c.data.getMessage(MSG_CM_WRN_007, "E/F 구분"));
            // WEIGHT 선택 
            ed_totWt2.setMandatory(false);
            ed_totWt2.options.validExp = "WEIGHT:no";
        }
    }

	$c.gus.cfRefreshMandSign(['tb_crryInCopino']);
};

