/**
 * @method
 * @name ed_frzTemper2_onviewchange
 * @description 반입 냉동온도 변경 이벤트 핸들러 함수
 * @hidden Y
 * @exception 
 */ 
scwin.ed_frzTemper2_onviewchange = function (info) {
    if (!$c.gus.cfValidate([ed_frzTemper2], null, true)) {
        ed_frzTemper2.setValue("");
    } else {
        if (hid_sizTyp2.getValue().substr(2, 2) == "RF" || hid_sizTyp2.getValue().substr(2, 2) == "RH") {
            if (ed_frzTemper2.getValue() == "") {
                hid_temperCls2.setValue("DRY");
                ed_rmk3.setValue(DsConstants.EDI_TEMPER_CLS_DRY);
            } else {
                hid_temperCls2.setValue("CEL");
                ed_rmk3.setValue(DsConstants.EDI_TEMPER_CLS_CEL);
            }

        }
    }
};

