scwin.lc_expimpClsCd2_onchange = function (info) {
    let expimpClsCd = lc_expimpClsCd2.getValue();
    if(expimpClsCd == "I") {
        // 수입
        ed_bookingNo2.setReadOnly(true);	// B/K 번호
        ed_doNo2.setReadOnly(false);	// D/o 번호					
        ed_blNo2.setReadOnly(false);	// BL 번호

    } else if(expimpClsCd == "E") {
        // 수출
        ed_bookingNo2.setReadOnly(false);	// B/K 번호
        ed_blNo2.setReadOnly(true);	// BL 번호
        ed_doNo2.setReadOnly(true);	// D/o 번호				
        ed_blNo2.setValue("");
    }

    lc_expimpClsCd1.setMandatory(false);
    lc_expimpClsCd1.options.validExp="수출입구분:no";
    lc_expimpClsCd2.setMandatory(false);
    lc_expimpClsCd2.options.validExp="수출입구분:no";		
};

